        "sql": [
          "customer_snapshot_v.`RealCID` = ddr_mimo_v.`RealCID` AND customer_snapshot_v.`DateID` = ddr_mimo_v.`DateID`",
          "--rt=FROM_RELATIONSHIP_TYPE_ONE_TO_MANY--"
        ],
        "instruction": [
          "Left Join on RealCID+DateID. MIMO rows only exist for customers with transactions."
        ]
      },
      {
        "id": "01f13716aac7137b9e787d179e5cfcd0",
        "left": {
          "identifier": "main.etoro_kpi.customer_snapshot_v",
          "alias": "customer_snapshot_v"
        },
        "right": {
          "identifier": "main.etoro_kpi.ddr_aum_v",
